INSERT INTO public.matriz_risco (id, pergunta_id, grau, narrativa_risco, controles_sugeridos, plano_acao, impacto, probabilidade) VALUES
    (md5('risco:q2:1')::uuid, md5('pergunta:q2')::uuid, 1, 'Risco alto: falha estrutural com alta probabilidade de impactos financeiros e de decisão. Possível impacto em confiabilidade dos números e decisões gerenciais.', 'Estruturar plano de contas mínimo e gerar DRE mensal com visão gerencial básica.', 'Revisar plano de contas atual e lacunas. ; Criar DRE mensal padrão. ; Definir responsável e calendário. ; Publicar relatório e registrar decisões. (meta: atingir Grau 2).', 2, 3),
    (md5('risco:q2:2')::uuid, md5('pergunta:q2')::uuid, 2, 'Risco médio-alto: controles existem, porém inconsistentes; risco relevante de falhas e retrabalho. Possível impacto em confiabilidade dos números e decisões gerenciais.', 'Formalizar uso gerencial da contabilidade (DRE/Balanço) e integrar minimamente com financeiro.', 'Incluir detalhamento gerencial (centros de custo). ; Padronizar lançamentos e rateios básicos. ; Criar integração manual com financeiro (extrato/AP/AR). ; Treinar time/contabilidade externa. (meta: atingir Grau 3).', 2, 2),
    (md5('risco:q2:3')::uuid, md5('pergunta:q2')::uuid, 3, 'Risco médio: processo parcialmente estruturado; risco moderado por ausência de padronização/integração. Possível impacto em confiabilidade dos números e decisões gerenciais.', 'Padronizar plano de contas com centros de custo e regras de apropriação/competência.', 'Implantar centros de custo/unidades. ; Definir regras de competência e conciliações. ; Criar relatório de variações (mês vs mês). ; Criar pacote gerencial mensal. (meta: atingir Grau 4).', 2, 2),
    (md5('risco:q2:4')::uuid, md5('pergunta:q2')::uuid, 4, 'Risco baixo: processo estruturado; risco residual operacional por exceções e disciplina de execução. Possível impacto em confiabilidade dos números e decisões gerenciais.', 'Instituir rotina de análise gerencial mensal (variações, drivers) com relatórios consistentes.', 'Integrar com BI/dashboard. ; Automatizar extrações e consistências. ; Revisar plano de contas anualmente. ; Auditar qualidade e tempestividade. (meta: atingir Grau 5).', 2, 1),
    (md5('risco:q2:5')::uuid, md5('pergunta:q2')::uuid, 5, 'Risco residual: maturidade elevada; risco concentrado em qualidade de dados, sistema e manutenção. Possível impacto em confiabilidade dos números e decisões gerenciais.', 'Integrar contabilidade à gestão estratégica (BI) e governança de dados contábeis.', 'Manter melhoria contínua; revisar periodicamente; auditar amostras; atualizar premissas e treinamento.', 2, 1),
