    (md5('risco:q17:1')::uuid, md5('pergunta:q17')::uuid, 1, 'Risco alto: falha estrutural com alta probabilidade de impactos financeiros e de decisão. Possível impacto em rentabilidade, capital de giro e estrutura de capital.', 'Implantar apuração básica de margem (bruta) e disciplina de precificação mínima.', 'Definir fórmula de margem e fontes de dados. ; Apurar margem bruta mensal. ; Revisar descontos/práticas. ; Treinar time comercial na leitura. (meta: atingir Grau 2).', 3, 3),
    (md5('risco:q17:2')::uuid, md5('pergunta:q17')::uuid, 2, 'Risco médio-alto: controles existem, porém inconsistentes; risco relevante de falhas e retrabalho. Possível impacto em rentabilidade, capital de giro e estrutura de capital.', 'Formalizar cálculo de margem por linha/produto e uso em decisões comerciais.', 'Criar margem por linha/produto. ; Padronizar relatório mensal. ; Definir política de desconto por margem mínima. ; Incluir margem no pipeline comercial. (meta: atingir Grau 3).', 3, 2),
    (md5('risco:q17:3')::uuid, md5('pergunta:q17')::uuid, 3, 'Risco médio: processo parcialmente estruturado; risco moderado por ausência de padronização/integração. Possível impacto em rentabilidade, capital de giro e estrutura de capital.', 'Padronizar relatórios de margem (produto/cliente/canal) com periodicidade definida.', 'Expandir para cliente/canal. ; Criar indicadores e metas. ; Revisão mensal com comercial/finanças. ; Analisar mix e oportunidades. (meta: atingir Grau 4).', 3, 2),
    (md5('risco:q17:4')::uuid, md5('pergunta:q17')::uuid, 4, 'Risco baixo: processo estruturado; risco residual operacional por exceções e disciplina de execução. Possível impacto em rentabilidade, capital de giro e estrutura de capital.', 'Integrar margem a orçamento, metas e gestão comercial (descontos/políticas).', 'Automatizar relatórios/dashboards. ; Criar simulações de preço/mix. ; Amarrar bônus/comissão a margem. ; Revisar trimestralmente políticas. (meta: atingir Grau 5).', 3, 1),
