    (md5('risco:q12:2')::uuid, md5('pergunta:q12')::uuid, 2, 'Risco médio-alto: controles existem, porém inconsistentes; risco relevante de falhas e retrabalho. Possível impacto em liquidez, previsibilidade e execução de pagamentos.', 'Formalizar processo de projeção de caixa (rolling) com premissas e responsáveis definidos.', 'Documentar premissas de projeção. ; Criar calendário de atualização (semanal/diário). ; Conectar vencimentos AP/AR ao fluxo. ; Criar checklist e evidência da atualização. (meta: atingir Grau 3).', 3, 2),
    (md5('risco:q12:3')::uuid, md5('pergunta:q12')::uuid, 3, 'Risco médio: processo parcialmente estruturado; risco moderado por ausência de padronização/integração. Possível impacto em liquidez, previsibilidade e execução de pagamentos.', 'Padronizar atualização e conciliação das premissas do fluxo; criar indicadores (dias de caixa, saldo mínimo).', 'Criar indicadores e gatilhos (caixa < mínimo). ; Implantar cenários base/conservador. ; Aprovar rotina com liderança (30 min/semana). ; Treinar equipe e padronizar comunicação. (meta: atingir Grau 4).', 3, 2),
    (md5('risco:q12:4')::uuid, md5('pergunta:q12')::uuid, 4, 'Risco baixo: processo estruturado; risco residual operacional por exceções e disciplina de execução. Possível impacto em liquidez, previsibilidade e execução de pagamentos.', 'Integrar fluxo ao contas a pagar/receber e instituir governança (reunião, gatilhos e decisões).', 'Integrar dados via sistema/planilha única. ; Automatizar importações (extrato/AP/AR). ; Criar dashboard executivo. ; Revisar processo trimestralmente. (meta: atingir Grau 5).', 3, 1),
